"""Minimal Linear GraphQL client.

Reads ``LINEAR_API_KEY`` from the environment. The CLI entrypoint
(``cli.main``) loads ``.env`` from the drain-cycle repo root before this
module is exercised; a shell-exported value still takes precedence.
Single-team scope: hardcoded to the ``Personal`` team per README §1 and
the US-A spec.
"""
from __future__ import annotations

import os
from typing import Any

import httpx

_ENDPOINT = "https://api.linear.app/graphql"
_TEAM_NAME = "Personal"
_PENDING_STATE_TYPES = ["backlog", "unstarted"]
_NO_PRIORITY_SORT_KEY = 5
"""Sort key for Linear's ``priority == 0`` (No priority). Linear encodes
1..4 as Urgent..Low; ``0`` means "unset" and must sort *after* Low, not
before Urgent. Picking 5 keeps the 1..4 ordering intact and pushes 0
to the end."""


def _post(query: str, variables: dict[str, Any] | None = None) -> dict[str, Any]:
    key = os.environ.get("LINEAR_API_KEY")
    if not key:
        raise RuntimeError("LINEAR_API_KEY is not set")
    resp = httpx.post(
        _ENDPOINT,
        headers={"Authorization": key, "Content-Type": "application/json"},
        json={"query": query, "variables": variables or {}},
        timeout=30.0,
    )
    resp.raise_for_status()
    body = resp.json()
    if "errors" in body:
        raise RuntimeError(f"Linear GraphQL errors: {body['errors']}")
    return body["data"]


def current_cycle_id() -> str:
    """Return the active cycle id for the configured team."""
    data = _post(
        """
        query CurrentCycle($name: String!) {
          teams(filter: { name: { eq: $name } }) {
            nodes {
              id
              activeCycle { id }
            }
          }
        }
        """,
        {"name": _TEAM_NAME},
    )
    nodes = data["teams"]["nodes"]
    if not nodes:
        raise RuntimeError(f"Linear team {_TEAM_NAME!r} not found")
    cycle = nodes[0].get("activeCycle")
    if not cycle:
        raise RuntimeError(f"Linear team {_TEAM_NAME!r} has no active cycle")
    return cycle["id"]


def _sort_pending_issues(issues: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """Sort by Linear priority (Urgent→Low→No-priority), tiebroken by ``sortOrder``.

    Linear encodes priority as 0=No priority, 1=Urgent, 2=High, 3=Medium, 4=Low.
    The quirk worth pinning down in a test: ``0`` must sort *after* ``4``, not
    before ``1``. We remap 0→``_NO_PRIORITY_SORT_KEY`` and leave 1..4 in place.
    """
    def key(issue: dict[str, Any]) -> tuple[int, float]:
        p = issue["priority"]
        return (p if p else _NO_PRIORITY_SORT_KEY, issue["sortOrder"])
    return sorted(issues, key=key)


def pending_issues(cycle_id: str) -> list[dict[str, Any]]:
    """Return every Todo/Backlog issue in the cycle, sorted for execution.

    No pagination: personal cycles fit comfortably in one page. If a cycle
    ever exceeds 100 pending issues, that's a planning problem, not a tool
    problem (see ``PRODUCT_RULES`` Rule A5 — focus is the multiplier).

    ``labels`` is flattened from the GraphQL ``{nodes: [{name}]}`` shape to
    a plain ``list[str]`` so downstream code (``repos.Repos.resolve`` per
    ABA-232) doesn't need to know the wire shape.
    """
    data = _post(
        """
        query CyclePending($cycleId: ID!, $stateTypes: [String!]!) {
          issues(
            filter: {
              cycle: { id: { eq: $cycleId } }
              state: { type: { in: $stateTypes } }
            }
            first: 100
          ) {
            nodes {
              id
              identifier
              title
              description
              priority
              sortOrder
              state { type name }
              labels { nodes { name } }
            }
          }
        }
        """,
        {"cycleId": cycle_id, "stateTypes": _PENDING_STATE_TYPES},
    )
    issues = data["issues"]["nodes"]
    for issue in issues:
        issue["labels"] = [node["name"] for node in issue["labels"]["nodes"]]
    return _sort_pending_issues(issues)


def get_issue(issue_id: str) -> dict[str, Any]:
    """Re-fetch an issue's current state by id."""
    data = _post(
        """
        query Issue($id: String!) {
          issue(id: $id) {
            id
            identifier
            title
            state { type name }
          }
        }
        """,
        {"id": issue_id},
    )
    issue = data["issue"]
    if issue is None:
        raise RuntimeError(f"Linear issue {issue_id!r} not found")
    return issue


def set_state(issue_id: str, state_name: str) -> None:
    """Transition an issue to the named workflow state.

    Resolves the state ID by name against the configured team and then issues
    an ``issueUpdate`` mutation. No caching — at cycle scale (≤ ~15 issues)
    the extra round-trip is irrelevant and the simpler code is easier to test.
    """
    state_id = _resolve_state_id(state_name)
    data = _post(
        """
        mutation IssueSetState($id: String!, $input: IssueUpdateInput!) {
          issueUpdate(id: $id, input: $input) {
            success
          }
        }
        """,
        {"id": issue_id, "input": {"stateId": state_id}},
    )
    if not data["issueUpdate"]["success"]:
        raise RuntimeError(
            f"Linear issueUpdate failed for {issue_id!r} → {state_name!r}"
        )


def _resolve_state_id(state_name: str) -> str:
    data = _post(
        """
        query WorkflowState($team: String!, $name: String!) {
          workflowStates(
            filter: {
              team: { name: { eq: $team } }
              name: { eq: $name }
            }
            first: 1
          ) {
            nodes { id }
          }
        }
        """,
        {"team": _TEAM_NAME, "name": state_name},
    )
    nodes = data["workflowStates"]["nodes"]
    if not nodes:
        raise RuntimeError(
            f"Linear workflow state {state_name!r} not found for team {_TEAM_NAME!r}"
        )
    return nodes[0]["id"]

"""Per-issue target-repo resolution (ABA-232).

The orchestrator used to be single-repo by construction: every worktree
landed under ``Path.cwd()``. Cycles in this workspace span multiple repos
by design — ``linear-workflow.md`` makes "Affected repos" part of the
six initiative-readiness fields, and the Ops slot deliberately holds
cross-repo maintenance issues — so each issue now carries a
``repo:<name>`` label and ``~/.drain-cycle/repos.yml`` maps the name to
an absolute path on disk.

Two distinct error types so the two halt paths can branch cleanly:

* ``RepoConfigError`` — startup-time problems (missing file, malformed
  YAML, empty, wrong top-level shape). The CLI catches it before any
  Linear traffic, prints to stderr, exits 1, and does **not** write a
  run-log entry — there is no cycle to log against yet.
* ``RepoResolutionError`` — per-issue problems (no ``repo:`` label,
  multiple ``repo:`` labels, name not in config, resolved path missing).
  The orchestrator catches it as a pre-spawn halt: write a run-log
  entry, print the matching ``Halt:`` line, exit 1. No revert is
  attempted because no Linear state was moved yet.
"""
from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path
from typing import Any

import yaml

_CONFIG_DISPLAY = "~/.drain-cycle/repos.yml"
_REPO_LABEL_PREFIX = "repo:"

_MISSING_CONFIG_HINT = (
    "create it mapping each repo: label to an absolute path, e.g.:\n\n"
    "  repos:\n"
    "    drain-cycle: /Users/you/src/drain-cycle\n"
    "    pde-skills:  /Users/you/src/pde-skills\n\n"
    "see docs/repos.example.yml for a template."
)


class RepoConfigError(RuntimeError):
    """``repos.yml`` is missing or malformed."""


class RepoResolutionError(RuntimeError):
    """An issue cannot be mapped to a target repo."""


def default_config_path() -> Path:
    """Resolved per call so tests can redirect via ``monkeypatch.setenv("HOME", ...)``."""
    return Path.home() / ".drain-cycle" / "repos.yml"


@dataclass(frozen=True)
class Repos:
    """Loaded ``repos.yml`` mapping (``name`` → absolute ``Path``)."""

    mapping: dict[str, Path]

    def resolve(self, issue: dict[str, Any]) -> Path:
        labels = [
            label
            for label in issue.get("labels", [])
            if label.startswith(_REPO_LABEL_PREFIX)
        ]
        if not labels:
            raise RepoResolutionError(f"no {_REPO_LABEL_PREFIX} label on issue")
        if len(labels) > 1:
            names = ", ".join(sorted(label[len(_REPO_LABEL_PREFIX):] for label in labels))
            raise RepoResolutionError(f"multiple {_REPO_LABEL_PREFIX} labels: {names}")
        name = labels[0][len(_REPO_LABEL_PREFIX):]
        try:
            path = self.mapping[name]
        except KeyError:
            raise RepoResolutionError(
                f'repo "{name}" not in {_CONFIG_DISPLAY}'
            ) from None
        if not path.exists():
            raise RepoResolutionError(f"resolved path {path} does not exist")
        return path


def load(path: Path | None = None) -> Repos:
    """Read ``repos.yml`` and return a validated ``Repos``.

    Tilde-prefixed paths inside the file are expanded against ``$HOME``.
    Every failure mode raises ``RepoConfigError`` with a message that
    names the on-disk problem so the operator can fix it without
    re-reading source.
    """
    if path is None:
        path = default_config_path()
    if not path.exists():
        raise RepoConfigError(
            f"{_CONFIG_DISPLAY} not found at {path}\n{_MISSING_CONFIG_HINT}"
        )
    try:
        data = yaml.safe_load(path.read_text())
    except yaml.YAMLError as exc:
        raise RepoConfigError(
            f"{_CONFIG_DISPLAY} is not valid YAML: {exc}"
        ) from None
    if data is None:
        raise RepoConfigError(f"{_CONFIG_DISPLAY} is empty")
    if not isinstance(data, dict) or "repos" not in data:
        raise RepoConfigError(
            f"{_CONFIG_DISPLAY} must have a top-level 'repos:' key"
        )
    block = data["repos"]
    if not isinstance(block, dict) or not block:
        raise RepoConfigError(
            f"{_CONFIG_DISPLAY} 'repos:' must be a non-empty mapping"
        )
    mapping: dict[str, Path] = {}
    for name, value in block.items():
        if not isinstance(value, str):
            raise RepoConfigError(
                f"{_CONFIG_DISPLAY} entry {name!r}: path must be a string"
            )
        mapping[str(name)] = Path(value).expanduser()
    return Repos(mapping=mapping)

